    'ancient_map_xinhai_1912_year' => '1912',
    'ancient_map_xinhai_1912_body' => '<p><em>ছিং গুও দাদি তু সিনহাই বিপ্লব (সিনহাই) অশান্ত স্থান-সূচক</em> — <strong>1912</strong> সালে (মেইজি 44তম বছর) শিংবেন মুদ্রণ সমবায়, ওসাকা (জাপান) দ্বারা প্রকাশিত। বর্তমানে ক্যালিফোর্নিয়া বিশ্ববিদ্যালয়, বার্কলে (যুক্তরাষ্ট্র)-এর গ্রন্থাগারে সংরক্ষিত।</p>',
